#include <stdio.h>
#include <stdlib.h>

typedef struct SegmentTree {
    int* arr;
    int* tree;
    int n;
} SegmentTree;

SegmentTree* createSegmentTree(int arr[], int n) {
    SegmentTree* st = (SegmentTree*)malloc(sizeof(SegmentTree));
    st->arr = (int*)malloc(n * sizeof(int));
    st->n = n;
    st->tree = (int*)calloc(4 * n, sizeof(int));
    for (int i = 0; i < n; i++) st->arr[i] = arr[i];
    return st;
}

void build(SegmentTree* st, int node, int start, int end) {
    if (start == end) {
        st->tree[node] = st->arr[start];
        return;
    }
    int mid = (start + end) / 2;
    build(st, 2 * node + 1, start, mid);
    build(st, 2 * node + 2, mid + 1, end);
    st->tree[node] = st->tree[2 * node + 1] + st->tree[2 * node + 2];
}

int query(SegmentTree* st, int node, int start, int end, int left, int right) {
    if (right < start || left > end) return 0;
    if (left <= start && right >= end) return st->tree[node];
    int mid = (start + end) / 2;
    return query(st, 2 * node + 1, start, mid, left, right) +
           query(st, 2 * node + 2, mid + 1, end, left, right);
}

void update(SegmentTree* st, int node, int start, int end, int idx, int val) {
    if (start == end) {
        st->arr[idx] = val;
        st->tree[node] = val;
        return;
    }
    int mid = (start + end) / 2;
    if (idx <= mid) {
        update(st, 2 * node + 1, start, mid, idx, val);
    } else {
        update(st, 2 * node + 2, mid + 1, end, idx, val);
    }
    st->tree[node] = st->tree[2 * node + 1] + st->tree[2 * node + 2];
}

void freeSegmentTree(SegmentTree* st) {
    free(st->arr);
    free(st->tree);
    free(st);
}

